def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0 or item > cap * 1.5:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        score = 0.0
        decay = 1.0
        additive = 0.0
        multiplicative = 1.0
        for j in range(1, 12):
            if j % 3 == 0:
                decay *= 0.85
            if ratio < (0.04 * j):
                partial_score = (j ** 2) * (1 - ratio)**3 * decay
                if cap % (j+2) == 0:
                    partial_score += np.log1p(j*j)
                else:
                    partial_score -= np.cbrt(j)
                score += partial_score
            else:
                exp_component = j * np.exp(-ratio * j/1.5) * decay / (j + 2)
                trig_component = np.sin(ratio * j) if ((cap+j) % 4 == 0) else -np.cos(ratio * j)
                score += exp_component + trig_component
            if j % 2 == 1:
                additive += np.tanh(score / (j + 1) * decay)
            else:
                additive -= np.arctan(score / (j + 1) * decay)
            if j % 5 == 0:
                multiplicative *= (1 + np.sin(j * ratio) * 0.1)
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if (residual + k) % 5 == 0:
                    score += np.log1p(residual)/ (k + 0.3) * (1 + 0.1 * k)
                    additive += np.sqrt(k) * np.tanh(residual / (cap+1))
                else:
                    score -= (residual ** 0.3) / (k + 1.0) * (1 - 0.05 * k)
                    additive -= np.cbrt(k) * np.arctan(abs(residual) / (cap+1))
            else:
                penalty = abs(residual) * 0.15 * k * (1 + 0.05 * np.sin(k * ratio))
                score -= penalty
                additive -= penalty / (k + 1)
        final_value = (score * multiplicative + additive) / (cap + 1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio * 1.2) * (1 + 0.05 * np.log1p(item))
        else:
            priorities[i] = -final_value * (np.log1p(cap) + np.sqrt(item)) * (1 - 0.1 * np.tanh(ratio))
    return priorities
